const express = require('express');
const mongodb = require('mongodb');

async function queryBuilder(filter, projection, sort) {
  // Connect to MongoDB
  const client = await mongodb.MongoClient.connect('mongodb://localhost:27017', { useNewUrlParser: true, useUnifiedTopology: true });

  // Choose the database and the collection
  const db = client.db('test');
  const collection = db.collection('users');

  // Execute the find method with the query built
  const results = await collection.find(filter, { projection }).sort(sort).toArray();

  // Close db connection
  client.close();

  return results;
}

const app = express();
app.use(express.json());

app.get('/users', async (req, res) => {
  const filter = req.query.filter || {};
  const projection = req.query.projection || {};
  const sort = req.query.sort || {};

  try {
    const users = await queryBuilder(filter, projection, sort);
    res.json(users);
  } catch(err) {
    console.error(err);
    res.status(500).send('Error querying the db');
  }
});

app.listen(3000, () => console.log('Server started on port 3000'));